 768px) {\n  .footer {\n    padding-top: 60px;\n    padding-bottom: 30px;\n  }\n  \n  .footer-menu li a,\n  .recent-blog a,\n  .footer p {\n    font-size: 13px;\n  }\n  \n  .lh-40 {\n    line-height: 30px;\n  }\n}\n\n@media (max-width: 480px) {\n  .footer {\n    padding-top: 40px;\n    padding-bottom: 20px;\n  }\n  \n  .footer-menu li a,\n  .recent-blog a,\n  .footer p {\n    font-size: 12px;\n  }\n  \n  .footer-socials li a {\n    font-size: 16px;\n    padding-left: 8px;\n  }\n}","/*=== MEDIA QUERY ===*/\n\n/* Ultra Mobile - Extra Small (320px - 400px) */\n@include mobile-xs{\n  /* Typography */\n  h1, .h1 {\n    font-size: 28px;\n    line-height: 32px;\n  }\n  h2, .h2 {\n    font-size: 22px;\n    line-height: 28px;\n  }\n  h3, .h3 {\n    font-size: 18px;\n    line-height: 24px;\n  }\n  h4, .h4 {\n    font-size: 16px;\n    line-height: 22px;\n  }\n  body {\n    font-size: 14px;\n  }\n\n  /* Navbar */\n  .navbar-brand img {\n    height: 50px !important;\n  }\n  .dropdown-menu {\n      display: none;\n      width: 100%;\n      text-align: center;\n  }\n  .navbar-nav li{\n      padding: 0px;\n  }\n  .navbar-nav {\n    margin-top: 15px;\n  }\n\n  /* Sections & Containers */\n  .section {\n    padding: 40px 0;\n  }\n  .container {\n    padding-left: 12px;\n    padding-right: 12px;\n  }\n  \n  /* Cards */\n  .card {\n    margin-bottom: 15px;\n  }\n  .card-body, .card > div[class*=\"p-\"] {\n    padding: 15px !important;\n  }\n  \n  /* Buttons */\n  .btn {\n    padding: 12px 20px;\n    font-size: 12px;\n    height: auto;\n    min-height: 44px;\n  }\n  \n  /* Forms */\n  input[type=email], input[type=password], input[type=text], input[type=tel] {\n    height: 44px;\n    font-size: 16px;\n  }\n  \n  /* Text utilities */\n  .text-lg {\n    font-size: 18px;\n  }\n  .lead {\n    font-size: 14px;\n  }\n  .number {\n    font-size: 36px;\n    line-height: 45px;\n  }\n}\n\n/* Small Mobile (400px - 480px) */\n@include mobile{\n  /* Typography */\n  h1, .h1 {\n    font-size: 32px;\n    line-height: 36px;\n  }\n  h2, .h2 {\n    font-size: 26px;\n    line-height: 32px;\n  }\n  h3, .h3 {\n    font-size: 20px;\n    line-height: 26px;\n  }\n  h4, .h4 {\n    font-size: 17px;\n    line-height: 23px;\n  }\n  body {\n    font-size: 14px;\n  }\n\n  /* Navbar */\n  .navbar-brand img {\n    height: 60px !important;\n  }\n  .ml-lg-4 {\n    margin-left: 0 !important;\n  }\n  .navbar-collapse {\n    padding-top: 15px;\n  }\n  .dropdown-menu {\n    display: none;\n    text-align: center;\n  }\n  .navbar-nav li{\n    padding: 0px;\n  }\n\n  /* Hero Section */\n  .slider h1 {\n    font-size: 32px;\n    line-height: 38px;\n  }\n  .slider {\n    padding: 80px 15px !important;\n  }\n\n  /* Text utilities */\n  .text-lg {\n    font-size: 24px;\n    line-height: 32px;\n  }\n  .lead {\n    font-size: 14px;\n  }\n  .number {\n    font-size: 44px;\n    line-height: 55px;\n  }\n\n  /* Sections */\n  .section {\n    padding: 50px 0;\n  }\n  \n  /* Cards */\n  .card {\n    margin-bottom: 20px;\n  }\n  \n  /* Buttons */\n  .btn {\n    padding: 14px 25px;\n    font-size: 13px;\n    min-height: 44px;\n  }\n\n  /* Forms */\n  input[type=email], input[type=password], input[type=text], input[type=tel] {\n    height: 44px;\n  }\n\n  /* Media elements */\n  .media{\n    display: block;\n  }\n  .media-body{\n    margin-top: 20px;\n  }\n}\n\n/* Tablet (480px - 768px) */\n@include tablet{\n  /* Typography */\n  h1, .h1 {\n    font-size: 36px;\n    line-height: 42px;\n  }\n  h2, .h2 {\n    font-size: 28px;\n    line-height: 34px;\n  }\n  h3, .h3 {\n    font-size: 22px;\n    line-height: 28px;\n  }\n  h4, .h4 {\n    font-size: 18px;\n    line-height: 24px;\n  }\n  body {\n    font-size: 15px;\n  }\n\n  /* Navbar */\n  .ml-lg-4 {\n    margin-left: 0 !important;\n  }\n\n  /* Sections */\n  .section {\n    padding: 60px 15px;\n  }\n  .container {\n    padding-left: 15px;\n    padding-right: 15px;\n  }\n\n  /* Cards - better spacing */\n  .card {\n    margin-bottom: 25px;\n  }\n\n  /* Media elements */\n  .media{\n    display: block;\n  }\n  .media-body{\n    margin-top: 20px;\n  }\n  .services .media img{\n    width: 100%!important;\n  }\n  \n  .dropdown-menu {\n    display: none;\n    text-align: center;\n  }\n  .navbar-nav li{\n    padding: 0px;\n  }\n\n  /* Column overrides for better tablet layout */\n  .col-sm-6 {\n    flex: 0 0 50%;\n    max-width: 50%;\n  }\n}\n\n/* Desktop (768px - 992px) */\n@include desktop{\n  .navbar-nav .dropdown-menu{\n    // display: block;\n  }\n  \n  /* Better spacing on desktop */\n  .section {\n    padding: 80px 0;\n  }\n}\n\n/* Large Desktop (992px - 1200px) */\n@include large-desktop{\n   .navbar-nav .dropdown-menu{\n    // display: block;\n  }\n   \n  .section {\n    padding: 80px 0;\n  }\n}"]}